<?php
session_start();
date_default_timezone_set('Asia/Kolkata');
require_once 'includes/config.php';
if (!isset($conn) || !($conn instanceof mysqli)) { die('Database connection not available. Check includes/config.php'); }
mysqli_report(MYSQLI_REPORT_OFF);
$conn->set_charset('utf8mb4');
if (!function_exists('h')) { function h($v): string { return htmlspecialchars((string)($v ?? ''), ENT_QUOTES, 'UTF-8'); } }
if (!function_exists('money')) { function money($v): string { return number_format((float)$v, 2); } }
if (!function_exists('tableExists')) { function tableExists(mysqli $conn, string $t): bool { $t=$conn->real_escape_string($t); $r=$conn->query("SHOW TABLES LIKE '{$t}'"); return $r && $r->num_rows>0; } }
if (!function_exists('nextNo')) { function nextNo(mysqli $conn, string $table, string $col, string $prefix, int $businessId): string { $like=$prefix.'%'; $sql="SELECT {$col} FROM {$table} WHERE business_id=? AND {$col} LIKE ? ORDER BY id DESC LIMIT 1"; $st=$conn->prepare($sql); if(!$st) return $prefix.'0001'; $st->bind_param('is',$businessId,$like); $st->execute(); $row=$st->get_result()->fetch_assoc(); $st->close(); $n=1; if($row){ $last=(string)$row[$col]; if(preg_match('/(\d+)$/',$last,$m)) $n=((int)$m[1])+1; } return $prefix.str_pad((string)$n,4,'0',STR_PAD_LEFT); } }
$userId=(int)($_SESSION['user_id']??0); $businessId=(int)($_SESSION['business_id']??1); if($userId<=0){ header('Location: ../login.php'); exit; }
$roleName = function_exists('currentRoleName') ? currentRoleName() : ($_SESSION['role_name'] ?? 'Admin');
if (!in_array($roleName, ['Super Admin','Admin','Manager','Billing'], true)) { die('Access denied.'); }

?>
<?php $currentPage='chit-collection'; $members=[]; $res=$conn->query("SELECT m.id,m.member_no,m.subscriber_name,g.group_name,g.installment_amount,g.id group_id FROM chit_members m INNER JOIN chit_groups g ON g.id=m.group_id WHERE m.business_id={$businessId} AND m.status='Active' ORDER BY m.subscriber_name"); if($res)while($r=$res->fetch_assoc())$members[]=$r; $payments=[]; $res=$conn->query("SELECT id,method_name FROM payment_methods WHERE is_active=1 ORDER BY method_name"); if($res)while($r=$res->fetch_assoc())$payments[]=$r; $member_id=(int)($_GET['member_id']??0);
if($_SERVER['REQUEST_METHOD']==='POST'){ $member_id=(int)$_POST['member_id']; $installment_id=(int)$_POST['installment_id']; $date=$_POST['collection_date']??date('Y-m-d'); $due=(float)$_POST['due_amount']; $paid=(float)$_POST['paid_amount']; $disc=(float)$_POST['discount_amount']; $pen=(float)$_POST['penalty_amount']; $net=$paid+$pen-$disc; $pm=($_POST['payment_method_id']!=='')?(int)$_POST['payment_method_id']:null; $ref=trim($_POST['reference_no']??''); $rem=trim($_POST['remarks']??''); $gid=0; foreach($members as $m){if((int)$m['id']===$member_id){$gid=(int)$m['group_id'];break;}} if($member_id<=0||$installment_id<=0||$paid<=0){$_SESSION['error']='Select member, installment and amount.';} else { $receipt=nextNo($conn,'chit_collections','receipt_no','CHR'.date('Ym'),$businessId); $st=$conn->prepare("INSERT INTO chit_collections (business_id,group_id,member_id,installment_id,receipt_no,collection_date,due_amount,paid_amount,discount_amount,penalty_amount,net_amount,payment_method_id,reference_no,remarks,created_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)"); $st->bind_param('iiiissdddddissi',$businessId,$gid,$member_id,$installment_id,$receipt,$date,$due,$paid,$disc,$pen,$net,$pm,$ref,$rem,$userId); }
}
?>

<?php if($_SERVER['REQUEST_METHOD']==='POST' && empty($_SESSION['error'])){ if($st->execute()){ $_SESSION['success']='Collection saved. Receipt: '.$receipt; $st->close(); header('Location: chit-ledger.php?member_id='.$member_id); exit; } else { $_SESSION['error']=$st->error; $st->close(); } } ?>

