<?php if(isset($_SESSION['success'])): ?><div class="alert alert-success alert-dismissible fade show"><?php echo h($_SESSION['success']); unset($_SESSION['success']); ?><button type="button" class="btn-close" data-bs-dismiss="alert"></button></div><?php endif; ?>
<?php if(isset($_SESSION['error'])): ?><div class="alert alert-danger alert-dismissible fade show"><?php echo h($_SESSION['error']); unset($_SESSION['error']); ?><button type="button" class="btn-close" data-bs-dismiss="alert"></button></div><?php endif; ?>

<div class="card"><div class="card-body"><h4>Chit Collection</h4><form method="post" class="row g-3"><div class="col-md-4"><label>Member *</label><select name="member_id" id="member_id" class="form-select" required><option value="">Select</option><?php foreach($members as $m): ?><option value="<?php echo (int)$m['id']; ?>" data-amount="<?php echo (float)$m['installment_amount']; ?>" <?php echo $member_id===$m['id']?'selected':''; ?>><?php echo h($m['member_no'].' - '.$m['subscriber_name'].' - '.$m['group_name']); ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label>Installment *</label><select name="installment_id" class="form-select" required><option value="">Select</option><?php $ins=$conn->query("SELECT ci.id,ci.installment_no,ci.due_date,g.group_name FROM chit_installments ci INNER JOIN chit_groups g ON g.id=ci.group_id WHERE ci.business_id={$businessId} AND ci.status='Open' ORDER BY ci.due_date"); if($ins)while($r=$ins->fetch_assoc()): ?><option value="<?php echo (int)$r['id']; ?>"><?php echo h($r['group_name'].' - #'.$r['installment_no'].' - '.date('d-m-Y',strtotime($r['due_date']))); ?></option><?php endwhile; ?></select></div><div class="col-md-2"><label>Date</label><input type="date" name="collection_date" class="form-control" value="<?php echo date('Y-m-d'); ?>"></div><div class="col-md-3"><label>Payment Method</label><select name="payment_method_id" class="form-select"><option value="">Select</option><?php foreach($payments as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo h($p['method_name']); ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Due Amount</label><input type="number" step="0.01" name="due_amount" id="due_amount" class="form-control" value="0"></div><div class="col-md-2"><label>Paid Amount</label><input type="number" step="0.01" name="paid_amount" class="form-control" required></div><div class="col-md-2"><label>Discount</label><input type="number" step="0.01" name="discount_amount" class="form-control" value="0"></div><div class="col-md-2"><label>Penalty</label><input type="number" step="0.01" name="penalty_amount" class="form-control" value="0"></div><div class="col-md-4"><label>Reference</label><input name="reference_no" class="form-control"></div><div class="col-md-12"><label>Remarks</label><textarea name="remarks" class="form-control"></textarea></div><div><button class="btn btn-primary">Save Collection</button></div></form></div></div><script>document.getElementById('member_id').addEventListener('change',function(){let o=this.options[this.selectedIndex];document.getElementById('due_amount').value=o.dataset.amount||0;});</script>

</div></div><?php include('includes/footer.php'); ?></div></div><?php include('includes/rightbar.php'); ?><?php include('includes/scripts.php'); ?></body></html>
